import tensorflow as tfmnist = tf.keras.datasets.mnist(train_x, train_y), (test_x, test_y) = mnist.load_data()x_train = train_x.reshape(60000, 784).astype('float32') / 255x_test = test_x.reshape(10000, 784).astype('float32') / 255print(x_train.shape)model = tf.keras.models.Sequential([    tf.keras.layers.Dense(128, activation='relu'),    tf.keras.layers.Dense(64, activation='relu'),    tf.keras.layers.Dense(32, activation='relu'),    tf.keras.layers.Dense(10, activation='softmax')])# 模型装配# 采用SGD优化器，学习率为 0.01;采用交叉熵损失函数，包含 Softmax ,设置测量指标为准确率model.compile(optimizer=tf.keras.optimizers.SGD(lr=0.01),              loss=tf.keras.losses.SparseCategoricalCrossentropy(from_logits=False),              metrics=['accuracy'])# 模型训练history = model.fit(          x_train,                           # 训练数据          train_y,                           # 数据标签          batch_size=32,                     # 批次大小          epochs=5,                          # 训练轮数          validation_data=(x_test, test_y),  # 测试集数据          validation_freq=1)                 # 验证的频率model.summary()# model.evaluate(x_test, test_y)x = x_test[1].reshape(1, 784)out = model.predict(x)print("实际值：", test_y[1])print('预测值：', tf.argmax(out, axis=1).numpy())